  gt::gt() |> 
  gt::cols_align('center') |>  
  gt::fmt_markdown('team') |> 
  gt::cols_hide(columns = win_pct) |> 
  gt::cols_label(team = "", !!!team_headers_with_images) |>
  gt::sub_missing(missing_text = '---') |> 
