                   domain = c("---", "2-0", "1-0", "1-1", "0-1", "0-2")
                 )) |>
  gt::tab_style(style = list(gt::cell_borders(
    sides = c("left"),
    color = "#acacac",
    weight = gt::px(2)
  )),
  locations = list(gt::cells_body(columns = everything()))) |> 
  gt::tab_style(style = list(gt::cell_borders(
    sides = c("right"),
    color = "#acacac",
    weight = gt::px(2)
  )),
